class Solution:
    def lastNonEmptyString(self, s):
        from collections import Counter
        freq = Counter(s)
        max_freq = max(freq.values())
        # Characters that appear at max_freq
        keep = set(c for c, f in freq.items() if f == max_freq)
        # Take characters from s in order, only last occurrence for each kept char
        # Simpler: iterate s in reverse to get last occurrences in reverse order
        seen = set()
        result = []
        for c in reversed(s):
            if c in keep and c not in seen:
                result.append(c)
                seen.add(c)
        return ''.join(reversed(result))

